(function (window) {
  window.env = window.env || {};

  // ============================================
  // Enterprise Verifier Proximity PWA
  // Runtime Configuration (generated by nginx entrypoint)
  // ============================================

  // ── Backend Configuration ──
  // Empty = same-origin proxy mode (Atlassian-style: nginx proxies /oid4vp/ and /api/)
  window["env"]["verifierBackendUrl"] = "${VERIFIER_BACKEND_URL}";

  // ── SSE Configuration ──
  window["env"]["sseTimeout"] = 120000; // 120 seconds

  // ── QR Code Configuration ──
  window["env"]["qrExpirationSeconds"] = 120; // 2 minutes

  // ── Multi-Tenancy Configuration ──
  // Atlassian-style: tenant = first segment of hostname
  window["env"]["tenant"] = window.location.hostname.split(".")[0];

  // ── Wallet URL ──
  // Relative path in Atlassian-style (same origin)
  window["env"]["walletUrl"] = "/wallet";

  // ── Legacy Configuration (Deprecated) ──
  window["env"]["logs_enabled"] = "${LOGS_ENABLED}";
  window["env"]["verifier_mode"] = "browser";
})(this);
